module calculator(
    input clk,
    input reset,
    input [1:0] operation,
    input [7:0] operand1,
    input [7:0] operand2,
    output [7:0] result
);

reg [7:0] calc_temp;

always @(posedge clk) begin
    if (reset) begin
        calc_temp <= 8'h00;
    end else begin
        case (operation)
            2'b00: calc_temp <= operand1 + operand2;
            2'b01: calc_temp <= operand1 - operand2;
        endcase
    end
end

assign result = calc_temp;

endmodule
